def main() -> None:
    out = Path(__file__).parent / "seed_catalog.json"
    entries = list(ENTRIES)
    for slug, title, url, topics in _CLINICAL_PMC:
        entries.append({
            "id": slug,
            "title": title,
            "source_url": url,
            "domain": "clinical",
            "trust_tier": "peer_reviewed",
            "license": "cc_by_4",
            "fetch_format": "html",
            "topics": topics,
            "denial_types": ["Medical Necessity", "Prior Authorization"],
            "source_org": "PMC",
            "priority": 2,
        })
    catalog = {
        "version": "1.0.0",
        "updated": datetime.now(UTC).date().isoformat(),
        "description": "Redistributable-safe seed corpus for Aetna/Cigna/UHC mednec+priorauth (500-case benchmark). Ingest with backend/scripts/ingest_library_seed.py; upload only at demo.",
        "entries": entries,
    }
    out.write_text(json.dumps(catalog, indent=2) + "\n", encoding="utf-8")
    print(f"Wrote {len(entries)} entries to {out}")


if __name__ == "__main__":
    main()
